mapper.select:
/* TM_PN60001_Dao_retrieveCerIssList */ SELECT ecs_elcpwstn_div_cd, ( SELECT cmmn_cd_nm FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_9002' AND cmmn_cd = ecs_elcpwstn_div_cd ) AS elcpwstn_nm, cer_delng_div_nm, cer_mntrng_strt_ym, cer_mntrng_end_ym, MONTHS_BETWEEN(TO_DATE(cer_mntrng_end_ym, 'yyyyMM'), TO_DATE(cer_mntrng_strt_ym, 'yyyyMM')) + 1 AS crtfc_mons, cer_amt, cer_iss_qy, rm_ctnt, frst_regist_dt, frst_rgstr_id, last_updt_dt, last_updusr_id, updt_rsn FROM tm_pn60001 WHERE SUBSTR(cer_mntrng_strt_ym, 0, 4) BETWEEN SUBSTR(#{strtDt}, 0, 4) AND SUBSTR(#{endDt}, 0, 4)
AND ecs_elcpwstn_div_cd = #{ecsElcpwstnDivCd}
ORDER BY ecs_elcpwstn_div_cd, cer_delng_div_nm, cer_mntrng_strt_ym

mapper.delete:
/* TM_PN60001_Dao_deleteCerIssList */
DELETE FROM
	tm_pn60001
WHERE
	ecs_elcpwstn_div_cd = #{ecsElcpwstnDivCd}
	AND cer_delng_div_nm = #{cerDelngDivNm}
